---@meta

-- Grid Protocol — Global Functions
-- LuaCATS annotations for the Grid firmware Lua API
-- https://github.com/intechstudio/grid-protocol
--
-- This file contains type stubs for GLOBAL functions (prefix "G" in
-- grid_protocol_bot.json).  Element-method stubs live in elements.lua.
--
-- Hand-enriched entries give full @param / @return / @overload detail.
-- Entries generated by scaffold_annotations.py are marked [scaffold].

---------------------------------------------------------------------------
-- MIDI
---------------------------------------------------------------------------

---Sends a standard MIDI message.
---@param channel integer MIDI channel (0–15)
---@param command integer MIDI status byte — e.g. 176 (CC), 144 (Note On)
---@param parameter1 integer First data byte (0–127)
---@param parameter2 integer Second data byte (0–127)
function midi_send(channel, command, parameter1, parameter2) end

---Sends a MIDI SysEx message.
---@param ... integer Variadic SysEx data bytes
function midi_sysex_send(...) end

---------------------------------------------------------------------------
-- Mapping / Math
---------------------------------------------------------------------------

---Linearly maps *value* from [from_min, from_max] to [to_min, to_max]
---and saturates the result to [to_min, to_max].
---@param value number Input value
---@param from_min number Source range minimum
---@param from_max number Source range maximum
---@param to_min number Target range minimum
---@param to_max number Target range maximum
---@return number mapped Mapped and clamped result
function map_saturate(value, from_min, from_max, to_min, to_max) end

---Calculates the intensity value for a single LED segment when
---visualising an endless-encoder position.
---@param value integer Current encoder value
---@param min integer Minimum of the value range
---@param max integer Maximum of the value range
---@param segment_index integer Zero-based LED segment index
---@param segment_count integer Total number of LED segments
---@return integer intensity Segment brightness (0–255)
function segment_calculate(value, min, max, segment_index, segment_count) end

---Clamps *value* between *min* and *max*.
---@param value number
---@param min number
---@param max number
---@return number clamped
function limit(value, min, max) end

---Returns the sign of a number: -1, 0, or 1.
---@param value number
---@return integer sign
function sign(value) end

---Returns a pseudo-random integer in [0, 255].
---@return integer value
function random8() end

