---------------------------------------------------------------------------
-- Auto-configuration helpers (user-overridable)
---------------------------------------------------------------------------

---Calculates the default MIDI channel from grid position.
---@param self any Element reference
---@return integer channel 0–15
function midi_auto_ch(self) end

---Calculates the default MIDI command type.
---Returns 144 (Note On) for button events, 176 (CC) for others.
---@param self any Element reference
---@return integer command
function midi_auto_cmd(self) end

---Calculates the default MIDI parameter 1 (note/CC number).
---@param self any Element reference
---@return integer param1 0–127
function midi_auto_p1(self) end

---Calculates the default MIDI parameter 2 (velocity/value).
---@param self any Element reference
---@return integer param2
function midi_auto_p2(self) end

---Calculates LED layer based on current event type.
---@param self any Element reference
---@return integer|nil layer 1 for button/pot, 2 for encoder, nil otherwise
function color_auto_layer(self) end

---Calculates LED intensity value based on element type and state.
---@param self any Element reference
---@param segment_index integer Segment index for endless encoders
---@return integer value 0–255
function color_auto_value(self, segment_index) end

---Calculates intensity response curve from color array.
---Processes -1 values as current LED colors.
---@param color_array table Array of color values
---@return table min_colors
---@return table mid_colors
---@return table max_colors
function color_curve(color_array) end
